#include <iostream>

using namespace std;

int fib(int n)
{
    if (n < 2) return n;

    int prev2 = 0, prev1 = 1;
    for (int i = 2; i <= n; i++)
    {
        int current = prev1 + prev2;
        prev2 = prev1;
        prev1 = current;
    }
    return prev1;
}

int main()
{
    cout << fib(5);

    return 0;
}

